1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life", () => {
5	  it("should return an empty set when given an empty set of living cells", () => {
6	    expect(nextGeneration(new Set<string>())).toEqual(new Set<string>());
7	  });
8	  it("should kill a single living cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration(new Set<string>(["0,0"]))).toEqual(new Set<string>());
10	  });
11	  it("should kill a living cell with only one live neighbor (underpopulation)", () => {
12	    expect(nextGeneration(new Set<string>(["0,0", "1,0"]))).toEqual(new Set<string>());
13	  });
14	  it("should keep a living cell alive with two live neighbors (survival)", () => {
15	    expect(nextGeneration(new Set<string>(["0,0", "1,0", "2,0"]))).toContain("1,0");
16	  });
17	  it.todo("should keep a living cell alive with three live neighbors (survival)");
18	  it.todo("should kill a living cell with four live neighbors (overpopulation)");
19	  it.todo("should bring a dead cell to life with exactly three live neighbors (reproduction)");
20	  it.todo("should handle living cells with negative coordinates");
21	});
