1	export function nextGeneration(livingCells: Set<string>): Set<string> {
2	  const survivors = new Set<string>();
3	  for (const cell of livingCells) {
4	    const liveNeighborCount = countLiveNeighbors(cell, livingCells);
5	    if (liveNeighborCount === 2 || liveNeighborCount === 3) {
6	      survivors.add(cell);
7	    }
8	  }
9	  return survivors;
10	}
11	
12	function countLiveNeighbors(cell: string, livingCells: Set<string>): number {
13	  const [x, y] = cell.split(",").map(Number);
14	  let count = 0;
15	  for (let dx = -1; dx <= 1; dx++) {
16	    for (let dy = -1; dy <= 1; dy++) {
17	      if (dx === 0 && dy === 0) continue;
18	      if (livingCells.has(`${x + dx},${y + dy}`)) count++;
19	    }
20	  }
21	  return count;
22	}
